// // This module decrements the count on every negative edge of the clock if the disable signal is low.
module counter_module (
    input clk,
    input reset,
    input enable,
    output reg [3:0] count
);

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 0;
        end else if (enable) begin
            count <= count + 1;
        end
    end
endmodule
